import sys

def get_type(data):
    if type(data) == str:
        return "string"
    elif type(data) == int:
        return "int"
    elif type(data) == float:
        return "float"
    elif type(data) == bool:
        return "bool"
    elif type(data) == list:
        return "list"
    elif type(data) == dict:
        return "dict"
    else:
        return "unknown"

def main():
    data = sys.argv[1]
    print(get_type(data))

if __name__ == "__main__":
    main()
